'use client';

import { useState } from 'react';
import Link from 'next/link';
import { getCampaignById } from '@/lib/mockCampaigns';
import { Heart, Share2, MapPin, Users, TrendingUp, ChevronLeft } from 'lucide-react';

interface CampaignDetailPageProps {
  params: {
    id: string;
  };
}

export default function CampaignDetailPage({ params }: CampaignDetailPageProps) {
  const campaign = getCampaignById(params.id);
  const [isShared, setIsShared] = useState(false);

  if (!campaign) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <h1 className="text-4xl font-bold text-gray-900 mb-4">Campaign Not Found</h1>
          <p className="text-gray-600 mb-8">The campaign you're looking for doesn't exist.</p>
          <Link href="/campaigns" className="btn-primary inline-block">
            Back to Campaigns
          </Link>
        </div>
      </div>
    );
  }

  const progressPercentage = Math.min((campaign.amountRaised / campaign.fundingGoal) * 100, 100);
  const daysLeft = Math.floor(Math.random() * 60) + 1;

  const urgencyColors = {
    Critical: 'bg-red-100 text-red-700 border-red-300',
    Urgent: 'bg-orange-100 text-orange-700 border-orange-300',
    High: 'bg-yellow-100 text-yellow-700 border-yellow-300',
    Normal: 'bg-blue-100 text-blue-700 border-blue-300',
  };

  const handleShare = () => {
    const text = `Support this campaign: ${campaign.title} - ${window.location.href}`;
    if (navigator.share) {
      navigator.share({
        title: campaign.title,
        text: campaign.description,
        url: window.location.href,
      });
    } else {
      navigator.clipboard.writeText(text);
      setIsShared(true);
      setTimeout(() => setIsShared(false), 2000);
    }
  };

  return (
    <>
      {/* Back Button */}
      <div className="bg-gray-50 border-b border-gray-200">
        <div className="container-max py-4">
          <Link href="/campaigns" className="inline-flex items-center gap-2 text-teal-600 hover:text-teal-700 font-semibold">
            <ChevronLeft size={20} />
            Back to Campaigns
          </Link>
        </div>
      </div>

      {/* Hero Image Section */}
      <section className="bg-gradient-to-br from-teal-100 to-blue-100 h-96 md:h-[500px] flex items-center justify-center">
        <div className="text-center">
          <Heart size={80} className="text-teal-600 mx-auto mb-4 opacity-50" />
          <p className="text-gray-600 font-semibold">{campaign.title}</p>
        </div>
      </section>

      {/* Main Content */}
      <section className="section-padding">
        <div className="container-max">
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            {/* Left Column - Campaign Details */}
            <div className="lg:col-span-2">
              {/* Header */}
              <div className="mb-8">
                <div className="flex flex-wrap gap-3 mb-4">
                  <span className={`text-sm font-bold px-4 py-2 rounded-full border ${urgencyColors[campaign.urgencyLevel]}`}>
                    {campaign.urgencyLevel}
                  </span>
                  <span className="text-sm font-semibold px-4 py-2 rounded-full bg-teal-100 text-teal-700">
                    {daysLeft} days left
                  </span>
                </div>
                <h1 className="text-4xl md:text-5xl font-bold text-gray-900 mb-4">
                  {campaign.title}
                </h1>
                <p className="text-xl text-gray-600">{campaign.description}</p>
              </div>

              {/* Location */}
              <div className="flex items-center gap-2 text-gray-600 mb-8">
                <MapPin size={20} className="text-teal-600" />
                <span>{campaign.location}</span>
              </div>

              {/* Full Description */}
              <div className="bg-gray-50 p-8 rounded-lg mb-8">
                <h2 className="text-2xl font-bold mb-4">About This Campaign</h2>
                <p className="text-gray-700 leading-relaxed mb-4">
                  {campaign.fullDescription}
                </p>
                <p className="text-gray-700 leading-relaxed">
                  Your contribution will directly support the following impact:
                </p>
                <div className="mt-4 p-4 bg-teal-50 border-l-4 border-teal-600">
                  <p className="font-semibold text-teal-900">{campaign.impact}</p>
                </div>
              </div>

              {/* Impact Breakdown */}
              <div className="mb-8">
                <h2 className="text-2xl font-bold mb-6">How Your Donation Helps</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="bg-blue-50 p-6 rounded-lg border border-blue-200">
                    <div className="text-3xl font-bold text-blue-600 mb-2">₹500</div>
                    <p className="text-gray-700">Provides essential medical supplies</p>
                  </div>
                  <div className="bg-green-50 p-6 rounded-lg border border-green-200">
                    <div className="text-3xl font-bold text-green-600 mb-2">₹1,000</div>
                    <p className="text-gray-700">Covers one day of treatment</p>
                  </div>
                  <div className="bg-orange-50 p-6 rounded-lg border border-orange-200">
                    <div className="text-3xl font-bold text-orange-600 mb-2">₹5,000</div>
                    <p className="text-gray-700">Supports a family for one week</p>
                  </div>
                  <div className="bg-purple-50 p-6 rounded-lg border border-purple-200">
                    <div className="text-3xl font-bold text-purple-600 mb-2">₹10,000</div>
                    <p className="text-gray-700">Provides complete care package</p>
                  </div>
                </div>
              </div>

              {/* Transparency Section */}
              <div className="bg-teal-50 p-8 rounded-lg border border-teal-200">
                <h2 className="text-2xl font-bold mb-4 text-teal-900">Our Commitment to Transparency</h2>
                <ul className="space-y-3 text-gray-700">
                  <li className="flex gap-3">
                    <span className="text-teal-600 font-bold">✓</span>
                    <span>100% of your donation goes directly to the campaign</span>
                  </li>
                  <li className="flex gap-3">
                    <span className="text-teal-600 font-bold">✓</span>
                    <span>You'll receive regular updates on campaign progress</span>
                  </li>
                  <li className="flex gap-3">
                    <span className="text-teal-600 font-bold">✓</span>
                    <span>Tax-deductible donation (80G certified)</span>
                  </li>
                  <li className="flex gap-3">
                    <span className="text-teal-600 font-bold">✓</span>
                    <span>Secure and encrypted payment processing</span>
                  </li>
                </ul>
              </div>
            </div>

            {/* Right Column - Donation Card */}
            <div className="lg:col-span-1">
              <div className="card card-padding sticky top-24">
                {/* Funding Progress */}
                <div className="mb-6">
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-2xl font-bold text-gray-900">
                      ₹{(campaign.amountRaised / 100000).toFixed(1)}L
                    </span>
                    <span className="text-sm font-semibold text-teal-600">
                      {Math.round(progressPercentage)}%
                    </span>
                  </div>
                  <p className="text-sm text-gray-600 mb-3">
                    of ₹{(campaign.fundingGoal / 100000).toFixed(1)}L goal
                  </p>
                  <div className="w-full bg-gray-200 rounded-full h-3">
                    <div
                      className="bg-teal-600 h-3 rounded-full transition-all duration-300"
                      style={{ width: `${progressPercentage}%` }}
                    />
                  </div>
                </div>

                {/* Donor Count */}
                <div className="flex items-center gap-2 text-gray-600 mb-6 pb-6 border-b border-gray-200">
                  <Users size={18} className="text-teal-600" />
                  <span className="text-sm">
                    <span className="font-bold text-gray-900">{campaign.donorCount}</span> donors
                  </span>
                </div>

                {/* CTA Buttons */}
                <div className="space-y-3 mb-6">
                  <a href="/donate" className="btn-primary w-full text-center block">
                    Donate Now
                  </a>
                  <button
                    onClick={handleShare}
                    className="w-full btn-secondary flex items-center justify-center gap-2"
                  >
                    <Share2 size={18} />
                    {isShared ? 'Copied!' : 'Share'}
                  </button>
                </div>

                {/* Trust Badges */}
                <div className="space-y-3 text-sm">
                  <div className="flex gap-2 items-start">
                    <span className="text-teal-600 font-bold text-lg">✓</span>
                    <span className="text-gray-600">Verified by AB Seva Foundation</span>
                  </div>
                  <div className="flex gap-2 items-start">
                    <span className="text-teal-600 font-bold text-lg">✓</span>
                    <span className="text-gray-600">80G Tax Deductible</span>
                  </div>
                  <div className="flex gap-2 items-start">
                    <span className="text-teal-600 font-bold text-lg">✓</span>
                    <span className="text-gray-600">Secure Payment</span>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Related Campaigns */}
      <section className="bg-gray-50 section-padding">
        <div className="container-max">
          <h2 className="section-title mb-12">Similar Campaigns</h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {[1, 2, 3].map((i) => (
              <Link key={i} href="/campaigns" className="card card-padding hover:shadow-lg transition-all">
                <div className="h-40 bg-gradient-to-br from-teal-100 to-blue-100 rounded-lg mb-4" />
                <h3 className="font-bold text-lg mb-2">Similar Campaign {i}</h3>
                <p className="text-sm text-gray-600 mb-4">Discover more ways to make an impact</p>
                <div className="text-teal-600 font-semibold text-sm">View Campaign →</div>
              </Link>
            ))}
          </div>
        </div>
      </section>

      {/* CTA Section */}
      <section className="bg-gradient-to-r from-teal-600 to-teal-700 text-white section-padding">
        <div className="container-max text-center">
          <h2 className="text-3xl md:text-4xl font-bold mb-4">
            Every Donation Matters
          </h2>
          <p className="text-lg text-teal-100 mb-8 max-w-2xl mx-auto">
            Your contribution will directly impact the lives of those in need. Join thousands of donors making a difference today.
          </p>
          <a href="/donate" className="inline-block px-8 py-4 bg-orange-500 hover:bg-orange-600 text-white font-bold rounded-full transition-colors">
            Make Your Donation
          </a>
        </div>
      </section>
    </>
  );
}
